// 從 router 轉發過來的 LINE 原始 body 取 replyToken
const body = $input.first().json.body || $input.first().json || {};
const events = body.events || [];
const replyToken = events.length ? (events[0].replyToken || null) : null;
return [{ json: { replyToken } }];

// 組戰果訊息
const replyToken = $('取 replyToken').first().json.replyToken;
const results = ($input.first().json.results) || [];
const today = $now.setZone('Asia/Taipei').toFormat('yyyy-MM-dd');

const pick = (p, kind) => {
  if (!p) return '';
  if (kind === 'title') return (p.title || []).map(t => t.plain_text).join('');
  if (kind === 'rich') return (p.rich_text || []).map(t => t.plain_text).join('');
  if (kind === 'select') return p.select ? p.select.name : '';
  if (kind === 'phone') return p.phone_number || '';
  if (kind === 'date') return p.date ? p.date.start : '';
  return '';
};

const lines = results.map(r => {
  const p = r.properties || {};
  const name = pick(p['姓名'], 'title') || '(未提供)';
  const phone = pick(p['電話'], 'phone');
  const city = pick(p['縣市'], 'select');
  const cat = pick(p['類型'], 'select');
  const budget = pick(p['預算'], 'rich');
  const acct = pick(p['帳號'], 'select');
  const t = pick(p['搶到時間'], 'date');
  const hhmm = t && t.length >= 16 ? t.slice(11, 16) : '';
  return `・${name} ${phone}｜${city} ${cat} ${budget}${hhmm ? `（${hhmm}${acct ? ' ' + acct : ''}）` : ''}`;
}).join('\n');

let text;
if (results.length > 0) {
  text = `🎯 KEIS 今日戰果 ${today}\n搶到 ${results.length} 筆：\n${lines}`;
} else {
  text = `😴 KEIS 今日戰果 ${today}\n目前 0 筆（還沒出貨或還沒搶到）\n\nℹ️ 系統若掛掉會另外收到「⚠ 沒心跳」通知；沒收到就代表監控正常運作中`;
}
return [{ json: { replyToken, text } }];
